// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

contract EmergencySystem {
    // ====== PATIENT STRUCT ======
    struct Patient {
        uint256 patientId;
        address walletAddress;
        string name;
        string location;
        uint256 registeredAt;
        bool isActive;
        uint256 emergencyCount;
    }
    
    struct Emergency {
        uint256 id;
        address caller;
        string location;
        uint256 timestamp;
        bool resolved;
        address assignedAmbulance;
        uint256 patientId;
    }
    
    struct AmbulanceLocation {
        int256 latitude;
        int256 longitude;
        uint256 lastUpdate;
        bool isActive;
    }
    
    struct DirectConnection {
        address ambulanceDriver;
        address admin;
        uint256 emergencyId;
        uint256 connectedAt;
        bool isActive;
    }
    
    
    mapping(uint256 => Emergency) public emergencies;
    mapping(address => bool) public registeredAmbulances;
    mapping(address => AmbulanceLocation) public ambulanceLocations;
    mapping(uint256 => address[]) public nearbyAmbulances;
    mapping(uint256 => DirectConnection[]) public directConnections;
    
    // ====== PATIENT MAPPINGS ======
    mapping(uint256 => Patient) public patients;
    mapping(address => uint256) public addressToPatientId;
    
    uint256 public patientCount;
    uint256 public emergencyCount;
    address public admin;
    int256 public proximityRadius = 5000; // 5 km in meters
    
    event PatientRegistered(uint256 indexed patientId, address indexed walletAddress, string name);
    event EmergencyCreated(uint256 indexed id, address indexed caller, string location);
    event AmbulanceAssigned(uint256 indexed emergencyId, address indexed ambulance);
    event EmergencyResolved(uint256 indexed emergencyId);
    event AmbulanceLocationUpdated(address indexed ambulance, int256 latitude, int256 longitude);
    event DirectConnectionEstablished(uint256 indexed emergencyId, address indexed driver, address indexed adminAddress);
    event NearbyAmbulancesIdentified(uint256 indexed emergencyId, uint256 count);
    
    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin");
        _;
    }
    
    constructor() {
        admin = msg.sender;
    }
    
    // ====== PATIENT REGISTRATION ======
    function registerPatient(string memory _name, string memory _location) external returns (uint256) {
        require(addressToPatientId[msg.sender] == 0, "Patient already registered");
        
        patientCount++;
        uint256 newPatientId = patientCount;
        
        patients[newPatientId] = Patient(
            newPatientId,
            msg.sender,
            _name,
            _location,
            block.timestamp,
            true,
            0
        );
        
        addressToPatientId[msg.sender] = newPatientId;
        emit PatientRegistered(newPatientId, msg.sender, _name);
        
        return newPatientId;
    }
    
    function updatePatientLocation(string memory _location) external {
        uint256 patientId = addressToPatientId[msg.sender];
        require(patientId != 0, "Patient not registered");
        
        patients[patientId].location = _location;
    }
    
    function getPatient(uint256 _patientId) external view returns (Patient memory) {
        return patients[_patientId];
    }
    
    function reportEmergency(string memory _location) external returns (uint256) {
        uint256 patientId = addressToPatientId[msg.sender];
        require(patientId != 0, "Patient not registered");
        
        emergencyCount++;
        emergencies[emergencyCount] = Emergency(
            emergencyCount,
            msg.sender,
            _location,
            block.timestamp,
            false,
            address(0),
            patientId
        );
        
        patients[patientId].emergencyCount++;
        emit EmergencyCreated(emergencyCount, msg.sender, _location);
        return emergencyCount;
    }
    
    function assignAmbulance(uint256 _emergencyId, address _ambulance) external onlyAdmin {
        require(!emergencies[_emergencyId].resolved, "Already resolved");
        emergencies[_emergencyId].assignedAmbulance = _ambulance;
        emit AmbulanceAssigned(_emergencyId, _ambulance);
    }
    
    function resolveEmergency(uint256 _emergencyId) external {
        require(emergencies[_emergencyId].assignedAmbulance == msg.sender, "Not assigned");
        emergencies[_emergencyId].resolved = true;
        emit EmergencyResolved(_emergencyId);
    }
    
    function registerAmbulance(address _ambulance) external onlyAdmin {
        registeredAmbulances[_ambulance] = true;
    }
    
    function updateAmbulanceLocation(int256 _latitude, int256 _longitude) external {
        require(registeredAmbulances[msg.sender], "Not registered ambulance");
        ambulanceLocations[msg.sender] = AmbulanceLocation({
            latitude: _latitude,
            longitude: _longitude,
            lastUpdate: block.timestamp,
            isActive: true
        });
        emit AmbulanceLocationUpdated(msg.sender, _latitude, _longitude);
    }
    
    function calculateDistance(int256 lat1, int256 lon1, int256 lat2, int256 lon2) internal pure returns (int256) {
        int256 latDiff = lat1 - lat2;
        int256 lonDiff = lon1 - lon2;
        return ((latDiff * latDiff) + (lonDiff * lonDiff)) / 1000; // Simplified distance calculation
    }
    
    function connectNearbyAmbulances(uint256 _emergencyId, int256 _latitude, int256 _longitude) external onlyAdmin {
        require(!emergencies[_emergencyId].resolved, "Emergency already resolved");
        
        address[] memory nearby = new address[](20); // Max 20 nearby ambulances
        uint256 count = 0;
        
        // Find all nearby ambulances
        for (uint256 i = 0; i < emergencyCount; i++) {
            address ambulanceAddr = emergencies[i].assignedAmbulance;
            if (registeredAmbulances[ambulanceAddr] && ambulanceLocations[ambulanceAddr].isActive) {
                int256 distance = calculateDistance(
                    _latitude,
                    _longitude,
                    ambulanceLocations[ambulanceAddr].latitude,
                    ambulanceLocations[ambulanceAddr].longitude
                );
                
                if (distance <= proximityRadius && count < 20) {
                    nearby[count] = ambulanceAddr;
                    
                    // Create direct connection with the nearby driver
                    DirectConnection memory newConnection = DirectConnection({
                        ambulanceDriver: ambulanceAddr,
                        admin: msg.sender,
                        emergencyId: _emergencyId,
                        connectedAt: block.timestamp,
                        isActive: true
                    });
                    
                    directConnections[_emergencyId].push(newConnection);
                    emit DirectConnectionEstablished(_emergencyId, ambulanceAddr, msg.sender);
                    
                    count++;
                }
            }
        }
        
        nearbyAmbulances[_emergencyId] = nearby;
        emit NearbyAmbulancesIdentified(_emergencyId, count);
    }
    
    function getNearbyAmbulances(uint256 _emergencyId) external view returns (address[] memory) {
        return nearbyAmbulances[_emergencyId];
    }
    
    function getDirectConnections(uint256 _emergencyId) external view returns (DirectConnection[] memory) {
        return directConnections[_emergencyId];
    }
    
    function setProximityRadius(int256 _radius) external onlyAdmin {
        proximityRadius = _radius;
    }
}

